/* ========================================================================
 * Light Bulb Functions
 * ======================================================================== */

static void light_bulb_init(light_bulb_state_t *light)
{
    light->on_off = false;
    light->brightness_level = 254;  /* Full brightness default */
    light->color_temperature = 370; /* Warm white (~2700K) */
    light->is_dimmable = true;
    light->transition_time = 500;   /* 500ms default transition */

    printf("[LIGHT] Light bulb initialized (dimmable, warm white)\n");
}

static void light_bulb_set_on_off(light_bulb_state_t *light, bool on)
{
    light->on_off = on;
    if (on) {
        hal_gpio_set_led(true);
        hal_pwm_set_duty((light->brightness_level * 100) / 254);
        printf("[LIGHT] Light turned ON (brightness=%d%%)\n",
               (light->brightness_level * 100) / 254);
    } else {
        hal_gpio_set_led(false);
        hal_pwm_set_duty(0);
        printf("[LIGHT] Light turned OFF\n");
    }
}

static void light_bulb_set_brightness(light_bulb_state_t *light, uint8_t level)
{
    if (level > 254) level = 254;
    light->brightness_level = level;

    if (light->on_off) {
        uint8_t percent = (level * 100) / 254;
        hal_pwm_set_duty(percent);
        printf("[LIGHT] Brightness set to %d%% (level=%d)\n", percent, level);
    }
}

static void light_bulb_handle_cluster_command(zigbee_device_context_t *ctx,
                                                uint16_t cluster_id,
                                                uint8_t command_id,
                                                const uint8_t *payload,
                                                uint16_t payload_len)
{
    (void)payload_len;

    switch (cluster_id) {
    case ZIGBEE_CLUSTER_ON_OFF:
        switch (command_id) {
        case 0x00: /* Off */
            light_bulb_set_on_off(&ctx->light, false);
            break;
        case 0x01: /* On */
            light_bulb_set_on_off(&ctx->light, true);
            break;
        case 0x02: /* Toggle */
            light_bulb_set_on_off(&ctx->light, !ctx->light.on_off);
            break;
        default:
            printf("[LIGHT] Unknown On/Off command: 0x%02X\n", command_id);
            break;
        }
        break;

    case ZIGBEE_CLUSTER_LEVEL_CONTROL:
        switch (command_id) {
        case 0x00: /* Move to Level */
            if (payload) {
                light_bulb_set_brightness(&ctx->light, payload[0]);
            }
            break;
        case 0x04: /* Move to Level (with On/Off) */
            if (payload) {
                light_bulb_set_brightness(&ctx->light, payload[0]);
                light_bulb_set_on_off(&ctx->light, payload[0] > 0);
            }
            break;
        default:
            printf("[LIGHT] Unknown Level Control command: 0x%02X\n", command_id);
            break;
        }
        break;

    default:
        printf("[LIGHT] Unhandled cluster 0x%04X command 0x%02X\n", cluster_id, command_id);
        break;
    }
}

