static void zigbee_factory_reset(zigbee_device_context_t *ctx)
{
    printf("\n[SYS] *** FACTORY RESET ***\n");

    /* Clear network configuration */
    memset(&ctx->network, 0, sizeof(zigbee_network_config_t));
    memset(&ctx->security, 0, sizeof(zigbee_security_context_t));
    ctx->num_discovered_networks = 0;
    ctx->permit_join_active = false;
    ctx->rejoin_attempts = 0;

    /* Reset light to defaults */
    light_bulb_init(&ctx->light);

    /* Clear NVM */
    uint8_t zeros[256] = {0};
    hal_nvm_write(0x0000, zeros, sizeof(zeros));

    ctx->state = DEVICE_STATE_INITIALIZED;
    ctx->factory_reset_pending = false;

    printf("[SYS] Factory reset complete. Device ready for new network join.\n");

    /* Blink LED rapidly to indicate factory reset */
    for (int i = 0; i < 6; i++) {
        hal_gpio_set_led(i % 2 == 0);
        hal_delay_ms(200);
    }
    hal_gpio_set_led(false);
}

